class Solution {
    public boolean doesAliceWin(String s) {
        int n = s.length();
        int[][] dp = new int[n + 1][n + 1];
        for (int i = n - 1; i >= 0; i--) {
            for (int j = i + 1; j <= n; j++) {
                int count = 0;
                for (int k = i; k < j; k++) {
                    if (isVowel(s.charAt(k))) {
                        count++;
                    }
                }
                if (count % 2 == 1) {
                    dp[i][j] = 1;
                } else {
                    dp[i][j] = -1;
                }
                for (int k = i + 1; k < j; k++) {
                    if (dp[i][k] == -1 && dp[k][j] == -1) {
                        dp[i][j] = 1;
                    }
                }
            }
        }
        return dp[0][n] == 1;
    }

    private boolean isVowel(char c) {
        return c == 'a' || c == 'e' || c == 'i' || c == 'o' || c == 'u';
    }
}

